            aOrbiterC = (((aWandererA + RotL64(aCross, 60U)) + RotL64(aCarry, 27U)) + 0x7A990BCBDEE4E53FULL) + aPhaseDOrbiterAssignSaltD[(((31U - aIndex) + 21U)) & S_SALT1];
            aOrbiterH = ((aWandererD + RotL64(aIngress, 3U)) + RotL64(aCarry, 39U)) + 0xE0EAAE2782FB76F8ULL;
            aOrbiterI = ((aWandererH + RotL64(aPrevious, 47U)) + 0x53A44C49A4505E85ULL) + aPhaseDOrbiterAssignSaltE[((aIndex + 23U)) & S_SALT1];
            aOrbiterA = (aWandererJ + RotL64(aCross, 41U)) + 0x649A97A85D677220ULL;
            //
            aOrbiterB = (aOrbiterB + aOrbiterE) + 0xB076AE39B1A875EEULL;
