            aOrbiterC = (aOrbiterC ^ aOrbiterI) ^ 0xA3D791B461DA3E62ULL;
            aOrbiterC = RotL64((aOrbiterC * 0xC6D72C378530E16FULL), 57U);
            //
            aOrbiterA = ((aOrbiterA + aOrbiterC) + 0xD5D5317F2E3AF359ULL) + aPhaseDOrbiterUpdateSaltB[((aIndex + 9U)) & S_SALT1];
