            aOrbiterB = ((aWandererG + RotL64(aPrevious, 18U)) + RotL64(aCarry, 57U)) + 0x73C1B169CBBE2F7DULL;
            aOrbiterK = ((aWandererK + RotL64(aIngress, 27U)) + RotL64(aCarry, 27U)) + 0x2ADA1318E57F3DC2ULL;
            //
            aOrbiterD = (aOrbiterD + aOrbiterC) + 0xCA58E96A69A9C73DULL;
            aOrbiterA = (aOrbiterA ^ aOrbiterD) ^ 0xE68EE69AD9639305ULL;
            aOrbiterA = RotL64((aOrbiterA * 0x83AA97936614D9A3ULL), 47U);
            //
            aOrbiterC = ((aOrbiterC + aOrbiterH) + 0xE3916FD0B83B9373ULL) + aPhaseBOrbiterUpdateSaltA[(((31U - aIndex) + 23U)) & S_SALT1];
            aOrbiterF = ((aOrbiterF ^ aOrbiterC) ^ 0xB0C066BBB6B4327CULL) ^ aPhaseBOrbiterUpdateSaltB[((aIndex + 11U)) & S_SALT1];
            aOrbiterF = RotL64((aOrbiterF * 0x2C622E89029B9FBBULL), 27U);
