            aOrbiterF = (aOrbiterF + aOrbiterK) + 0x10B095E436DD6F56ULL;
            aOrbiterD = ((aOrbiterD ^ aOrbiterF) ^ 0x5AC9784F5339CF54ULL) ^ aPhaseBOrbiterUpdateSaltC[((aIndex + 18U)) & S_SALT1];
            aOrbiterD = RotL64((aOrbiterD * 0xAF2A3DB8AF5E48D9ULL), 21U);
            //
            aOrbiterH = (aOrbiterH + aOrbiterA) + 0x9B187023673EFB0EULL;
            aOrbiterK = (aOrbiterK ^ aOrbiterH) ^ 0xFBB9C16E89289226ULL;
            aOrbiterK = RotL64((aOrbiterK * 0x0AAE732EE912EA0FULL), 3U);
            //
            aOrbiterK = ((aOrbiterK + aOrbiterB) + 0x98C249962A80C0B8ULL) + aPhaseBOrbiterUpdateSaltF[(((31U - aIndex) + 28U)) & S_SALT1];
            aOrbiterC = (aOrbiterC ^ aOrbiterK) ^ 0x6917350E6BD2EB1DULL;
            aOrbiterC = RotL64((aOrbiterC * 0x344B0F1FD9165A73ULL), 53U);
            //
            aOrbiterA = (aOrbiterA + aOrbiterF) + 0x31CD5FBEDD57C562ULL;
            aOrbiterB = (aOrbiterB ^ aOrbiterA) ^ 0x38BC3AB849C78301ULL;
            aOrbiterB = RotL64((aOrbiterB * 0x4BD302C1F222FC21ULL), 37U);
            //
            aIngress = RotL64(aOrbiterD, 3U) ^ aOrbiterH;
            aIngress = aIngress + (aOrbiterF ^ RotL64(aOrbiterA, 27U));
            aIngress = aIngress + (RotL64(aOrbiterK, 47U) ^ aOrbiterC);
            aIngress = aIngress + RotL64(aOrbiterB, 13U);
            aIngress = TwistMix64::DiffuseB((aIngress + aScatter));
            //
            aWandererK = aWandererK ^ ((RotL64(aCross, 35U) + RotL64(aOrbiterB, 37U)) + aOrbiterH);
