            aWandererI = aWandererI ^ ((RotL64(aIngress, 47U) + RotL64(aOrbiterC, 13U)) + aOrbiterF);
            aWandererG = aWandererG + (((RotL64(aScatter, 41U) + RotL64(aOrbiterA, 29U)) + aOrbiterH) + RotL64(aCarry, 43U));
