            aOrbiterE = RotL64((aOrbiterE * 0x7713ED0EC8FB4533ULL), 57U);
            //
            aOrbiterJ = (aOrbiterJ + aOrbiterE) + 0xB6DA95A5B04139EEULL;
            aOrbiterD = (aOrbiterD ^ aOrbiterJ) ^ 0xFCAD2C2FABE4B446ULL;
            aOrbiterD = RotL64((aOrbiterD * 0xCE4D42FA67B0AB15ULL), 13U);
