            aOrbiterK = (aOrbiterK + aOrbiterD) + 0xEFB09092ECCF2914ULL;
            aOrbiterC = ((aOrbiterC ^ aOrbiterK) ^ 0x3E4C111C3EA69996ULL) ^ aPhaseAOrbiterUpdateSaltA[((aIndex + 26U)) & S_SALT1];
            aOrbiterC = RotL64((aOrbiterC * 0x1C241957D0542F0DULL), 47U);
            //
            aOrbiterE = (aOrbiterE + aOrbiterA) + 0xC1B3782F55DDE4D6ULL;
