            //
            aOrbiterC = ((aOrbiterC + aOrbiterI) + 0xC85722BF8C905D04ULL) + aPhaseAOrbiterUpdateSaltD[((aIndex + 15U)) & S_SALT1];
            aOrbiterJ = (aOrbiterJ ^ aOrbiterC) ^ 0xEA7EFE859D219C32ULL;
            aOrbiterJ = RotL64((aOrbiterJ * 0xF4D113CBBF16D8CBULL), 5U);
