            aWandererB = aWandererB ^ ((RotL64(aScatter, 43U) + aOrbiterK) + RotL64(aOrbiterA, 39U));
            aWandererI = aWandererI + ((((RotL64(aPrevious, 47U) + aOrbiterC) + RotL64(aOrbiterF, 47U)) + RotL64(aCarry, 39U)) + aPhaseAWandererUpdateSaltA[(((31U - aIndex) + 23U)) & S_SALT1]);
