            aWandererH = aWandererH + ((((RotL64(aIngress, 5U) + RotL64(aOrbiterE, 12U)) + aOrbiterI) + RotL64(aCarry, 29U)) + aPhaseAWandererUpdateSaltF[((aIndex + 9U)) & S_SALT1]);
