            aOrbiterG = (aWandererD + RotL64(aCross, 53U)) + 0xB9BBF1EDC23329EAULL;
            aOrbiterH = (aWandererK + RotL64(aScatter, 29U)) + 0x57CE07C5D4B01BB7ULL;
            aOrbiterC = (aWandererC + RotL64(aPrevious, 19U)) + 0xAA77EFE974A80EA5ULL;
            //
            aOrbiterJ = (aOrbiterJ + aOrbiterK) + 0x27F441FA4E33566CULL;
            aOrbiterD = ((aOrbiterD ^ aOrbiterJ) ^ 0x68417CA25C4119B7ULL) ^ aPhaseGOrbiterUpdateSaltB[(((31U - aIndex) + 12U)) & S_SALT1];
            aOrbiterD = RotL64((aOrbiterD * 0x308F8E6F7CD35CEFULL), 41U);
            //
            aOrbiterK = (aOrbiterK + aOrbiterI) + 0x3A59C147AA1423F5ULL;
