            //
            aOrbiterA = (aOrbiterA + aOrbiterE) + 0x83D066D8E95AFDA2ULL;
            aOrbiterB = (aOrbiterB ^ aOrbiterA) ^ 0xEF8C6D6163071612ULL;
            aOrbiterB = RotL64((aOrbiterB * 0xD30EFA7CEFB5AA4DULL), 27U);
            //
            aOrbiterI = (aOrbiterI + aOrbiterG) + 0x68F754A5EF9A6EEDULL;
            aOrbiterA = ((aOrbiterA ^ aOrbiterI) ^ 0x82283486B4211A03ULL) ^ aPhaseGOrbiterUpdateSaltF[((aIndex + 29U)) & S_SALT1];
            aOrbiterA = RotL64((aOrbiterA * 0xD6951186090C276FULL), 51U);
            //
            aOrbiterD = (aOrbiterD + aOrbiterF) + 0xE1769876A9D055ABULL;
            aOrbiterH = (aOrbiterH ^ aOrbiterD) ^ 0x661448A5D35B0B84ULL;
            aOrbiterH = RotL64((aOrbiterH * 0x1841FBD8784A04F9ULL), 43U);
            //
            aOrbiterH = ((aOrbiterH + aOrbiterC) + 0x283E6D21FC7750E6ULL) + aPhaseGOrbiterUpdateSaltC[(((31U - aIndex) + 5U)) & S_SALT1];
            aOrbiterK = (aOrbiterK ^ aOrbiterH) ^ 0x15309BBD9DD8DE88ULL;
            aOrbiterK = RotL64((aOrbiterK * 0xFDF96112F5990A0DULL), 47U);
            //
            aOrbiterE = (aOrbiterE + aOrbiterH) + 0xF641C211AD60296AULL;
            aOrbiterJ = (aOrbiterJ ^ aOrbiterE) ^ 0xFE92686999D2E0B4ULL;
            aOrbiterJ = RotL64((aOrbiterJ * 0xD6931DC5D59C872DULL), 37U);
            //
            aOrbiterB = (aOrbiterB + aOrbiterJ) + 0xFA8785067B81D9C8ULL;
            aOrbiterG = (aOrbiterG ^ aOrbiterB) ^ 0xEB2B1FD208C23243ULL;
            aOrbiterG = RotL64((aOrbiterG * 0xBA33E85AFC36A8AFULL), 21U);
