            aOrbiterC = (aOrbiterC + aOrbiterB) + 0x371F5A3251168EB0ULL;
            aOrbiterI = ((aOrbiterI ^ aOrbiterC) ^ 0x05434928BE3546D4ULL) ^ aPhaseGOrbiterUpdateSaltA[(((31U - aIndex) + 21U)) & S_SALT1];
