            //
            aOrbiterF = (aOrbiterF + aOrbiterA) + 0xC699C8CA929F15ADULL;
            aOrbiterC = (aOrbiterC ^ aOrbiterF) ^ 0x7BEE810A0B4513EAULL;
            aOrbiterC = RotL64((aOrbiterC * 0xD2CC525889EC46F9ULL), 53U);
            //
            aOrbiterG = (aOrbiterG + aOrbiterD) + 0xC24EDE164069AB9FULL;
            aOrbiterE = (aOrbiterE ^ aOrbiterG) ^ 0xAF5367B7303AD31DULL;
            aOrbiterE = RotL64((aOrbiterE * 0x1EB7335E9A8198B7ULL), 5U);
            //
            aIngress = RotL64(aOrbiterA, 35U) ^ aOrbiterK;
            aIngress = aIngress + (aOrbiterJ ^ RotL64(aOrbiterH, 20U));
            aIngress = aIngress + (RotL64(aOrbiterC, 37U) ^ aOrbiterG);
            aIngress = aIngress + (aOrbiterB ^ RotL64(aOrbiterE, 53U));
            aIngress = aIngress + (RotL64(aOrbiterD, 11U) ^ aOrbiterF);
            aIngress = aIngress + RotL64(aOrbiterI, 58U);
            aIngress = TwistMix64::DiffuseA((aIngress + aScatter));
            //
            aWandererH = aWandererH ^ ((RotL64(aCross, 51U) + aOrbiterI) + RotL64(aOrbiterD, 24U));
            aWandererF = aWandererF + ((RotL64(aPrevious, 3U) + aOrbiterE) + RotL64(aOrbiterA, 39U));
            aWandererC = aWandererC ^ ((RotL64(aScatter, 19U) + aOrbiterC) + RotL64(aOrbiterH, 13U));
