            aScatter = TwistMix64::DiffuseA(aScatter);
            //
            aOrbiterH = ((aWandererG + RotL64(aIngress, 39U)) + 0xA6BC87A869450FD7ULL) + aPhaseHOrbiterAssignSaltF[((aIndex + 13U)) & S_SALT1];
            aOrbiterI = ((aWandererE + RotL64(aCross, 53U)) + RotL64(aCarry, 35U)) + 0x7276B75407D80AD4ULL;
            aOrbiterF = ((aWandererH + RotL64(aScatter, 3U)) + 0x44DC6D9C350C7B3CULL) + aPhaseHOrbiterAssignSaltB[(((31U - aIndex) + 7U)) & S_SALT1];
            aOrbiterJ = ((aWandererB + RotL64(aPrevious, 57U)) + RotL64(aCarry, 23U)) + 0x2C9C74FD0766FD0CULL;
            aOrbiterB = (aWandererA + RotL64(aIngress, 28U)) + 0x247BB1E7DF60C114ULL;
            aOrbiterE = (aWandererD + RotL64(aCross, 47U)) + 0xEB03B2C906AA1523ULL;
